#include <stdio.h>

int main() {
    int n, a;
    scanf("%d %d", &n, &a);
    if (a % 2 == 1) {
        printf("%d\n", (a + 1) / 2);
    } else {
        printf("%d\n", n / 2 - a / 2 + 1);
    }
    return 0;
}
```

